#' Scaffold Test Files for Target Language
#'
#' Generates idiomatic test harnesses in the target language based on existing
#' spec files. Creates native test files that load specs and write cache results.
#'
#' @param lang Target language ("R", "python", "rust")
#' @param spec_dir Directory containing spec files (default: "spec")
#' @param test_dir Directory to write test files (default: "tests")
#' @param verify_functions Logical, whether to verify target functions exist
#'
#' @return Paths to created test files (invisibly)
#' @export
#'
#' @examples
#' \dontrun{
#' # Scaffold Python tests
#' sv_scaffold("python")
#' 
#' # Scaffold R tests with verification
#' sv_scaffold("R", verify_functions = TRUE)
#' }
sv_scaffold <- function(lang, spec_dir = "spec", test_dir = "tests", verify_functions = FALSE) {

  lang <- tolower(lang)
  supported_langs <- c("r", "python", "rust")

  if (!lang %in% supported_langs) {
    cli::cli_abort("Unsupported language: {lang}. Supported: {paste(supported_langs, collapse = ', ')}")
  }

  if (!fs::dir_exists(spec_dir)) {
    cli::cli_abort("Spec directory does not exist: {spec_dir}")
  }

  # Get spec files
  spec_files <- fs::dir_ls(spec_dir, glob = "*.json")

  if (length(spec_files) == 0) {
    cli::cli_warn("No spec files found in {spec_dir}")
    return(invisible(character(0)))
  }

  # Create target test directory
  lang_test_dir <- switch(lang,
    "r" = fs::path(test_dir, "testthat"),
    "python" = fs::path(test_dir, "pytest"),
    "rust" = fs::path(test_dir, "rust")
  )

  if (!fs::dir_exists(lang_test_dir)) {
    fs::dir_create(lang_test_dir, recurse = TRUE)
    cli::cli_inform("Created test directory: {lang_test_dir}")
  }

  # Process each spec file
  created_files <- character(0)

  for (spec_file in spec_files) {
    spec_data <- jsonlite::read_json(spec_file)
    spec_name <- spec_data$name

    if (verify_functions) {
      .verify_function_exists(spec_data, lang)
    }

    test_file <- switch(lang,
      "r" = .create_r_test(spec_data, lang_test_dir),
      "python" = .create_python_test(spec_data, lang_test_dir),
      "rust" = .create_rust_test(spec_data, lang_test_dir)
    )

    created_files <- c(created_files, test_file)
    cli::cli_inform("Created {lang} test: {test_file}")
  }

  # Create helper files if needed
  if (lang == "python") {
    .create_python_helper(lang_test_dir)
  } else if (lang == "rust") {
    .create_rust_helper(lang_test_dir)
  }

  invisible(created_files)
}

# Verify that target function exists (T-09)
.verify_function_exists <- function(spec_data, lang) {
  func_name <- spec_data$function_name

  if (lang == "r") {
    # Try to find function in global environment or attached packages
    if (!exists(func_name, mode = "function")) {
      cli::cli_warn("Function '{func_name}' not found in R environment")
    }
  } else if (lang == "python") {
    # This would require more complex verification - skip for now
    # Could use reticulate to check if function exists in Python module
    cli::cli_inform("Python function verification not implemented yet")
  }
}

# Create R testthat test file
.create_r_test <- function(spec_data, test_dir) {
  spec_name <- spec_data$name
  func_name <- spec_data$function_name

  test_content <- glue::glue('
test_that("{spec_name} produces expected output", {{
  # Load spec
  spec_file <- here::here("spec", "{spec_name}.v1.json")
  spec_data <- jsonlite::read_json(spec_file)

  # Execute function with spec inputs
  result <- do.call({func_name}, spec_data$inputs)

  # Compare with expected output
  expect_equal(result, spec_data$output, tolerance = 1e-12)

  # Write cache result
  run_id <- digest::digest(Sys.time())
  cache_dir <- here::here("results", "cache", run_id)
  if (!fs::dir_exists(cache_dir)) fs::dir_create(cache_dir, recurse = TRUE)

  cache_data <- list(
    spec_name = "{spec_name}",
    language = "R",
    output = result,
    timestamp = Sys.time()
  )

  cache_file <- fs::path(cache_dir, "{spec_name}.R.json")
  jsonlite::write_json(cache_data, cache_file, auto_unbox = TRUE, pretty = TRUE)
}})
', .trim = TRUE)

  test_file <- fs::path(test_dir, paste0("test-", spec_name, ".R"))
  writeLines(test_content, test_file)

  return(test_file)
}

